// ===== module imports (6.0.0; generated by build/convert-esm-pass2.mjs) =====
import { safeLog } from './03-memory-management.js';
import { saveUserPreferencesToCloud } from './05-preferences-cloud-sync.js';
import { state } from './state.js';

// ============================================
// V5.52.0: COUNTDOWN WARNING FUNCTIONALITY
// ============================================

/**
    * Load warning settings from localStorage
    */
function loadWarningSettings() {
    try {
        const stored = localStorage.getItem('countdownWarningSettings');
        if (stored) {
            const parsed = JSON.parse(stored);
            state.warningSettings = { ...state.warningSettings, ...parsed };
            safeLog.log('[Warning] Settings loaded:', state.warningSettings);
        }
        // V5.52.1: Apply custom colors on load
        applyWarningColors();
    } catch (e) {
        console.error('[Warning] Error loading settings:', e);
    }
}

/**
    * Save warning settings to localStorage
    */
function saveWarningSettings() {
    try {
        localStorage.setItem('countdownWarningSettings', JSON.stringify(state.warningSettings));
        safeLog.log('[Warning] Settings saved:', state.warningSettings);
        // V5.52.1: Apply custom colors after saving
        applyWarningColors();
        // V5.53: Also save to cloud
        saveUserPreferencesToCloud();
    } catch (e) {
        console.error('[Warning] Error saving settings:', e);
    }
}

/**
    * V5.52.1: Apply custom warning colors to CSS variables
    */
function applyWarningColors() {
    const root = document.documentElement;
    root.style.setProperty('--warning-color-subtle', state.warningSettings.colorSubtle);
    root.style.setProperty('--warning-color-medium', state.warningSettings.colorMedium);
    root.style.setProperty('--warning-color-urgent', state.warningSettings.colorUrgent);
}

/**
    * V5.52.1: Reset warning colors to defaults
    */
function resetWarningColors() {
    state.warningSettings.colorSubtle = '#fbbf24';
    state.warningSettings.colorMedium = '#f97316';
    state.warningSettings.colorUrgent = '#ef4444';
    
    // Update color inputs in modal
    const subtleInput = document.getElementById('warning-color-subtle');
    const mediumInput = document.getElementById('warning-color-medium');
    const urgentInput = document.getElementById('warning-color-urgent');
    
    if (subtleInput) subtleInput.value = state.warningSettings.colorSubtle;
    if (mediumInput) mediumInput.value = state.warningSettings.colorMedium;
    if (urgentInput) urgentInput.value = state.warningSettings.colorUrgent;
    
    applyWarningColors();
}

/**
    * Get the appropriate warning class based on settings and time remaining
    * @param {number} secondsRemaining - Seconds until bell
    * @param {boolean} isQuickBell - Whether this is a quick bell timer
    * @returns {string|null} CSS class to apply, or null if no warning
    */
function getWarningClass(secondsRemaining, isQuickBell = false) {
    if (!state.warningSettings.enabled) return null;
    if (isQuickBell && !state.warningSettings.quickBells) return null;
    if (!isQuickBell && !state.warningSettings.scheduledBells) return null;
    if (secondsRemaining > state.warningSettings.time || secondsRemaining <= 0) return null;
    
    // Calculate intensity based on time remaining
    const timeRatio = secondsRemaining / state.warningSettings.time;
    let intensity;
    
    if (timeRatio > 0.5) {
        intensity = 'subtle';
    } else if (timeRatio > 0.2) {
        intensity = 'medium';
    } else {
        intensity = 'urgent';
    }
    
    // If user set a fixed intensity, use that instead
    if (state.warningSettings.intensity !== 'auto') {
        // Progressive: start at subtle, escalate based on user's max
        if (state.warningSettings.intensity === 'subtle') {
            intensity = 'subtle';
        } else if (state.warningSettings.intensity === 'medium') {
            intensity = timeRatio > 0.5 ? 'subtle' : 'medium';
        } else if (state.warningSettings.intensity === 'urgent') {
            intensity = timeRatio > 0.5 ? 'subtle' : (timeRatio > 0.2 ? 'medium' : 'urgent');
        }
    }
    
    return `warning-${state.warningSettings.style}-${intensity}`;
}

/**
    * Apply warning effect to visual cue container
    * @param {number} secondsRemaining - Seconds until bell
    * @param {boolean} isQuickBell - Whether this is a quick bell timer
    */
function applyWarningEffect(secondsRemaining, isQuickBell = false) {
    const container = document.getElementById('visual-cue-container');
    if (!container) return;
    
    const newClass = getWarningClass(secondsRemaining, isQuickBell);
    
    // Remove old warning class if different
    if (state.currentWarningClass && state.currentWarningClass !== newClass) {
        container.classList.remove(state.currentWarningClass);
    }
    
    // Apply new warning class
    if (newClass && newClass !== state.currentWarningClass) {
        container.classList.add(newClass);
        state.currentWarningClass = newClass;
    } else if (!newClass && state.currentWarningClass) {
        container.classList.remove(state.currentWarningClass);
        state.currentWarningClass = null;
    }
    
    // Also apply to PiP window if open
    if (state.pipWindow && !state.pipWindow.closed) {
        const pipContainer = state.pipWindow.document.getElementById('pip-visual');
        if (pipContainer) {
            // Remove all warning classes first
            pipContainer.className = pipContainer.className.replace(/warning-\S+/g, '').trim();
            if (newClass) {
                pipContainer.classList.add(newClass);
            }
        }
    }
}

/**
    * Clear all warning effects
    */
function clearWarningEffects() {
    const container = document.getElementById('visual-cue-container');
    if (container && state.currentWarningClass) {
        container.classList.remove(state.currentWarningClass);
    }
    state.currentWarningClass = null;
    
    // Also clear from PiP
    if (state.pipWindow && !state.pipWindow.closed) {
        const pipContainer = state.pipWindow.document.getElementById('pip-visual');
        if (pipContainer) {
            pipContainer.className = pipContainer.className.replace(/warning-\S+/g, '').trim();
        }
    }
}

/**
    * Open warning settings modal
    */
function openWarningSettingsModal() {
    const modal = document.getElementById('warning-settings-modal');
    if (!modal) return;
    
    // Populate form with current settings
    document.getElementById('warning-enabled').checked = state.warningSettings.enabled;
    document.getElementById('warning-time').value = state.warningSettings.time;
    document.getElementById('warning-style').value = state.warningSettings.style;
    document.getElementById('warning-intensity').value = state.warningSettings.intensity;
    document.getElementById('warning-scheduled-bells').checked = state.warningSettings.scheduledBells;
    document.getElementById('warning-quick-bells').checked = state.warningSettings.quickBells;
    
    // V5.52.1: Populate color inputs
    document.getElementById('warning-color-subtle').value = state.warningSettings.colorSubtle;
    document.getElementById('warning-color-medium').value = state.warningSettings.colorMedium;
    document.getElementById('warning-color-urgent').value = state.warningSettings.colorUrgent;
    
    modal.classList.remove('hidden');
}

/**
    * Close warning settings modal
    */
function closeWarningSettingsModal() {
    const modal = document.getElementById('warning-settings-modal');
    if (modal) {
        modal.classList.add('hidden');
    }
    // Stop any preview animation
    stopWarningPreview();
}

/**
    * Save warning settings from modal
    */
function saveWarningSettingsFromModal() {
    state.warningSettings.enabled = document.getElementById('warning-enabled').checked;
    state.warningSettings.time = parseInt(document.getElementById('warning-time').value) || 60;
    state.warningSettings.style = document.getElementById('warning-style').value;
    state.warningSettings.intensity = document.getElementById('warning-intensity').value;
    state.warningSettings.scheduledBells = document.getElementById('warning-scheduled-bells').checked;
    state.warningSettings.quickBells = document.getElementById('warning-quick-bells').checked;
    
    // V5.52.1: Save custom colors
    state.warningSettings.colorSubtle = document.getElementById('warning-color-subtle').value;
    state.warningSettings.colorMedium = document.getElementById('warning-color-medium').value;
    state.warningSettings.colorUrgent = document.getElementById('warning-color-urgent').value;
    
    saveWarningSettings();
    closeWarningSettingsModal();
    
    // Clear any existing warnings so they recalculate
    clearWarningEffects();
}

/**
    * Preview warning effect in modal
    */
let warningPreviewTimeout = null;
function previewWarningEffect() {
    const preview = document.getElementById('warning-preview');
    if (!preview) return;
    
    // Get current form values
    const style = document.getElementById('warning-style').value;
    const intensity = document.getElementById('warning-intensity').value;
    
    // V5.52.1: Apply current color settings from form for preview
    const root = document.documentElement;
    root.style.setProperty('--warning-color-subtle', document.getElementById('warning-color-subtle').value);
    root.style.setProperty('--warning-color-medium', document.getElementById('warning-color-medium').value);
    root.style.setProperty('--warning-color-urgent', document.getElementById('warning-color-urgent').value);
    
    // Clear previous preview
    preview.className = 'mx-auto w-24 h-24 bg-gray-800 rounded-lg flex items-center justify-center';
    
    // Apply preview class
    const previewClass = `warning-${style}-${intensity}`;
    preview.classList.add(previewClass);
    
    // Stop after 3 seconds
    if (warningPreviewTimeout) clearTimeout(warningPreviewTimeout);
    warningPreviewTimeout = setTimeout(() => {
        stopWarningPreview();
    }, 3000);
}

/**
    * Stop warning preview
    */
function stopWarningPreview() {
    const preview = document.getElementById('warning-preview');
    if (preview) {
        preview.className = 'mx-auto w-24 h-24 bg-gray-800 rounded-lg flex items-center justify-center';
    }
    if (warningPreviewTimeout) {
        clearTimeout(warningPreviewTimeout);
        warningPreviewTimeout = null;
    }
}


// ===== module exports (6.0.0) =====
export {
    applyWarningEffect,
    clearWarningEffects,
    closeWarningSettingsModal,
    loadWarningSettings,
    openWarningSettingsModal,
    previewWarningEffect,
    resetWarningColors,
    saveWarningSettingsFromModal,
};
